+fn artifact_dir() -> PathBuf {
+    let unique = format!(
+        "benchmark-e2e-{}-{}",
+        std::process::id(),
+        std::time::SystemTime::now()
+            .duration_since(std::time::UNIX_EPOCH)
+            .expect("clock")
+            .as_nanos()
+    );
+    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
+        .join("tests")
+        .join("artifacts")
+        .join("benchmark_e2e")
+        .join(unique)
+}
